query:
UPDATE articles SET 
  title = REGEXP_REPLACE(
    REGEXP_REPLACE(
      REGEXP_REPLACE(
        REGEXP_REPLACE(title, 'Top Picks & Reviews', ''),
        'Top Pi Products', ''
      ),
      'best best best best best ', 'Best '
    ),
    '  +', ' '
  ),
  slug = REGEXP_REPLACE(
    REGEXP_REPLACE(
      REGEXP_REPLACE(
        REGEXP_REPLACE(slug, 'top-picks-reviews', ''),
        'top-pi-products', ''
      ),
      'best-best-best-best-best-', 'best-'
    ),
    '--+', '-'
  )
WHERE title LIKE '%Top Picks%' OR title LIKE '%best best%' OR slug LIKE '%best-best%';

